#pragma once
#include <cstdint>

// Generated by Claude based upon:
// PS/2 Set 1 scan codes → Mac CGKeyCodes
// https://gist.github.com/eegrok/949034
static uint32_t translateKey(uint16_t scancode)
{
    // Base scan codes (no E0 prefix)
    static const uint8_t base[256] = {
        // 0x00
        0xFF,
        // 0x01 Esc
        0x35,
        // 0x02-0x0D: 1,2,3,4,5,6,7,8,9,0,-,=
        0x12, 0x13, 0x14, 0x15, 0x17, 0x16, 0x1A, 0x1C, 0x19, 0x1D, 0x1B, 0x18,
        // 0x0E Backspace, 0x0F Tab
        0x33, 0x30,
        // 0x10-0x19: Q,W,E,R,T,Y,U,I,O,P
        0x0C, 0x0D, 0x0E, 0x0F, 0x11, 0x10, 0x20, 0x22, 0x1F, 0x23,
        // 0x1A [, 0x1B ]
        0x21, 0x1E,
        // 0x1C Enter, 0x1D LCtrl
        0x24, 0x3B,
        // 0x1E-0x26: A,S,D,F,G,H,J,K,L
        0x00, 0x01, 0x02, 0x03, 0x05, 0x04, 0x26, 0x28, 0x25,
        // 0x27 ;, 0x28 ', 0x29 `
        0x29, 0x27, 0x32,
        // 0x2A LShift, 0x2B backslash
        0x38, 0x2A,
        // 0x2C-0x35: Z,X,C,V,B,N,M,,,.,/
        0x06, 0x07, 0x08, 0x09, 0x0B, 0x2D, 0x2E, 0x2B, 0x2F, 0x2C,
        // 0x36 RShift, 0x37 Numpad*, 0x38 LAlt, 0x39 Space, 0x3A CapsLock
        0x3C, 0x43, 0x3A, 0x31, 0x39,
        // 0x3B-0x44: F1-F10
        0x7A, 0x78, 0x63, 0x76, 0x60, 0x61, 0x62, 0x64, 0x65, 0x6D,
        // 0x45 NumLock, 0x46 ScrollLock
        0x47, 0xFF,
        // 0x47-0x4E: Num7,8,9,-,4,5,6,+
        0x59, 0x5B, 0x5C, 0x4E, 0x56, 0x57, 0x58, 0x45,
        // 0x4F-0x53: Num1,2,3,0,.
        0x53, 0x54, 0x55, 0x52, 0x41,
        // 0x54-0x55
        0xFF, 0xFF,
        // 0x56 ISO extra key (between LShift and Z on European keyboards)
        0x0A,
        // 0x57 F11, 0x58 F12
        0x67, 0x6F,
        // 0x59-0xFF
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF
    };

    // Extended scan codes (E0 prefix, bit 8 set)
    static const uint8_t ext[256] = {
        // 0x00-0x1B
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF,
        // 0x1C Numpad Enter, 0x1D RCtrl
        0x4C, 0x3E,
        // 0x1E-0x34
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF,
        // 0x35 Numpad/, 0x36 RShift, 0x37 PrintScreen, 0x38 RAlt
        0x4B, 0x3C, 0xFF, 0x3D,
        // 0x39-0x46
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        // 0x47 Home, 0x48 Up, 0x49 PgUp, 0x4A, 0x4B Left, 0x4C, 0x4D Right, 0x4E
        0x73, 0x7E, 0x74, 0xFF, 0x7B, 0xFF, 0x7C, 0xFF,
        // 0x4F End, 0x50 Down, 0x51 PgDn, 0x52 Insert, 0x53 Delete
        0x77, 0x7D, 0x79, 0x72, 0x75,
        // 0x54-0x5A
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        // 0x5B LWin, 0x5C RWin, 0x5D Apps
        0x37, 0x36, 0xFF,
        // 0x5E-0xFF
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
        0xFF, 0xFF
    };

    uint8_t sc = scancode & 0xFF;
    return (scancode & 0x100) ? ext[sc] : base[sc];
}
